import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SafeCommandExecution {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a command to execute: ");
        String userInput = reader.readLine();

        // Secure way to execute the command using ProcessBuilder
        ProcessBuilder processBuilder = new ProcessBuilder();
        processBuilder.command("bash", "-c", userInput); // Execute the command in a secure manner

        Process process = processBuilder.start();

        BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String outputLine;

        System.out.println("Output of the command:");
        while ((outputLine = outputReader.readLine()) != null) {
            System.out.println(outputLine);
        }
    }
}

